package repository; import model.Book; import java.util.*; public class InMemoryBookRepository implements BookRepository{private Map<String,Book> data=new HashMap<>(); public void save(Book b){data.put(b.getIsbn(),b);} public Optional<Book> findByIsbn(String i){return Optional.ofNullable(data.get(i));} public Collection<Book> findAll(){return data.values();} public void delete(String i){data.remove(i);}}